<template>
    <view class="contain">
        <view class="title">
            <view>
                性別を選択
            </view>
            <view class="fu">
                ※複数選択可
            </view>
        </view>
        <view class="content">
            <view class="item" v-for="(item,index) in array" @click="changeTab(index)">
                <view class="itemLeft">
                    <view class="unselect" v-if="current != index"></view>
                    <view class="selected" v-if="current == index">
                        <view class="fill"></view>
                    </view>
                </view>
                <view class="itemRight" :style="current == index? 'color:#1D1D1F;' : 'color: #AAAAAA' "
                    v-text="item.value"></view>
            </view>
        </view>
    </view>
</template>

<script>
    export default {
        data() {
            return {
                current: 0,
                array: [{
                        value: "男性"
                    },
                    {
                        value: "女性"
                    },
                    {
                        value: "Xジェンダー"
                    }
                ]
            }
        },
        methods: {
            changeTab(e) {
                this.current = e
            }
        }
    }
</script>

<style lang="scss">
    .contain {
        border-top: 2upx solid #D2D2D7;
    }

    .title {
        display: flex;
        align-items: center;
        padding: 60upx 40upx 40upx;
        font-size: 32upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;

        .fu {
            color: #AAAAAA !important;
            margin-left: 32upx;
        }
    }

    .item {
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 28upx 38upx;
        border-bottom: 2upx solid #EAEAEA;

        .itemLeft {
            margin-right: 28upx;
        }

        .unselect {
            width: 40upx;
            height: 40upx;
            background: #FFFFFF;
            opacity: 1;
            box-sizing: border-box;
            border: 2upx solid #707070;
            border-radius: 50%;
        }

        .selected {
            width: 40upx;
            height: 40upx;
            background: #FFFFFF;
            border: 2upx solid #1A73E8;
            border-radius: 50%;
            box-sizing: border-box;
            padding: 6upx;

            .fill {
                width: 100%;
                height: 100%;
                background: #1A73E8;
                border-radius: 50%;
            }
        }

    }
</style>
